const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
// Twilio inbound voice posts: From, To, CallSid, etc.
const from = body.From || null;
const to = body.To || null;
const callSid = body.CallSid || null;
if (!callSid) return { json: { _bad: true } };
return { json: { from: from, to: to, call_sid: callSid } };

const ctx = $('Parse Twilio').item.json;
const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
const clientId = row && row.client_id;
const cfg = (row && row.configuration) || {};
const sipUri = cfg.vapi_sip_uri || process.env.VAPI_SIP_URI || 'sip:placeholder@vapi.ai';
// Build TwiML to bridge the inbound call to Vapi via SIP.
const twiml = '<?xml version="1.0" encoding="UTF-8"?><Response><Dial><Sip>' + sipUri + '?lead_phone=' + encodeURIComponent(ctx.from || '') + '&amp;client_id=' + encodeURIComponent(clientId || '') + '</Sip></Dial></Response>';
return { json: { twiml: twiml, client_id: clientId, ctx: ctx } };
